INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (72, "直感、あったんですよね。\nアオイさんほど詳しくはないですが、\nわたしも草花が好きなので。\nこの人とは仲良くなれそう、みたいな。", 72017, 1, 0, 1, 11, 0, 0, 1, 10);
