INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (72, "だからわたし、\n勇気を出して言ってみたんです！\nお友だちになりませんか、って。", 72021, 1, 0, 1, 11, 0, 0, 1, 10);
