INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (82, "vo_asb_0821", 82012, 0, "", "", 21, "", "", "vo_asb", 0);
INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (82, "その頃わたくしは、\nスカウトをお受けしておりました。\nミサト様いわく、わたくしには保育士の\n『天賦の才』があるそうで。", 82013, 1, 0, 1, 11, 0, 0, 1, 10);
INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (82, "", 82014, 0, "", "", 91, "", "", 0, 0);
